// Ventana de 30 dias terminando ayer (UTC).
const toDate = new Date();
toDate.setUTCDate(toDate.getUTCDate() - 1);
const fromDate = new Date(toDate);
fromDate.setUTCDate(fromDate.getUTCDate() - 29);
const toIso = toDate.toISOString().slice(0, 10);
const fromIso = fromDate.toISOString().slice(0, 10);
const sinceUnix = Math.floor(fromDate.getTime() / 1000);
const untilUnix = Math.floor((toDate.getTime() + 86400000) / 1000);
return [{ json: { from: fromIso, to: toIso, since: sinceUnix, until: untilUnix } }];

// Extrae el page_access_token de la Page Drean (id 257587170945975).
const PAGE_ID = '257587170945975';
const pages = items[0]?.json?.data || [];
const page = pages.find(p => p.id === PAGE_ID);
if (!page || !page.access_token) {
  throw new Error(`Page ${PAGE_ID} no encontrada o sin access_token. Verifica que el system user tenga la Page asignada.`);
}
// Preserva el date range del item anterior
const dates = $('Compute date range').first().json;
return [{ json: { ...dates, page_id: PAGE_ID, page_access_token: page.access_token } }];

// Combina los 3 outputs de insights diarios (KPIs + Fans Total + Reactions)
// en filas para meta_page_daily.
const PAGE_ID = '257587170945975';
const out = new Map();

for (const item of items) {
  const data = item.json?.data || [];
  for (const m of data) {
    const name = m.name;
    for (const v of m.values || []) {
      const fecha = (v.end_time || '').slice(0, 10);
      if (!fecha) continue;
      let row = out.get(fecha);
      if (!row) {
        row = {
          fecha,
          page_id: PAGE_ID,
          impressions: 0,
          impressions_unique: 0,
          impressions_organic: 0,
          reach_organic: 0,
          engaged_users: 0,
          post_engagements: 0,
          page_views: 0,
          fans_total: null,
          fan_adds: 0,
          fan_removes: 0,
          consumptions: 0,
          video_views: 0,
          reactions_like: 0,
          reactions_love: 0,
          reactions_wow: 0,
          reactions_haha: 0,
          reactions_sorry: 0,
          reactions_anger: 0,
        };
        out.set(fecha, row);
      }
      const val = typeof v.value === 'number' ? v.value : 0;
      if (name === 'page_impressions') row.impressions = val;
      else if (name === 'page_impressions_unique') row.impressions_unique = val;
      else if (name === 'page_impressions_organic_v2') row.impressions_organic = val;
      else if (name === 'page_impressions_organic_unique_v2') row.reach_organic = val;
      else if (name === 'page_engaged_users') row.engaged_users = val;
      else if (name === 'page_post_engagements') row.post_engagements = val;
      else if (name === 'page_views_total') row.page_views = val;
      else if (name === 'page_fans') row.fans_total = val;
      else if (name === 'page_fan_adds_unique') row.fan_adds = val;
      else if (name === 'page_fan_removes_unique') row.fan_removes = val;
      else if (name === 'page_consumptions') row.consumptions = val;
      else if (name === 'page_video_views') row.video_views = val;
      else if (name === 'page_actions_post_reactions_like_total') row.reactions_like = val;
      else if (name === 'page_actions_post_reactions_love_total') row.reactions_love = val;
      else if (name === 'page_actions_post_reactions_wow_total') row.reactions_wow = val;
      else if (name === 'page_actions_post_reactions_haha_total') row.reactions_haha = val;
      else if (name === 'page_actions_post_reactions_sorry_total') row.reactions_sorry = val;
      else if (name === 'page_actions_post_reactions_anger_total') row.reactions_anger = val;
    }
  }
}
return [...out.values()].map(json => ({ json }));

// Normaliza FB posts a meta_posts (platform=facebook).
const PAGE_ID = '257587170945975';
const out = [];
const posts = items[0]?.json?.data || [];
for (const p of posts) {
  const insightsArr = p.insights?.data || [];
  const m = {};
  for (const i of insightsArr) {
    if (Array.isArray(i.values) && i.values.length > 0) {
      const v = i.values[0].value;
      if (typeof v === 'number') {
        m[i.name] = v;
      } else if (typeof v === 'object' && v !== null) {
        // post_reactions_by_type_total devuelve un objeto {like: N, love: N, ...}
        m[i.name] = Object.values(v).reduce((acc, n) => acc + (typeof n === 'number' ? n : 0), 0);
      }
    }
  }
  const mediaType = p.attachments?.data?.[0]?.media_type || null;
  const thumbUrl = p.attachments?.data?.[0]?.media?.image?.src || null;
  out.push({ json: {
    platform: 'facebook',
    post_id: p.id,
    cuenta_id: PAGE_ID,
    fecha_post: p.created_time || new Date().toISOString(),
    permalink: p.permalink_url || null,
    message: p.message || null,
    media_type: mediaType,
    thumbnail_url: thumbUrl,
    impressions: m.post_impressions || 0,
    reach: m.post_impressions_unique || 0,
    engagement: m.post_engaged_users || 0,
    reactions: m.post_reactions_by_type_total || 0,
    likes: 0,
    comments: 0,
    shares: 0,
    saved: 0,
    video_views: m.post_video_views || 0,
    clicks: m.post_clicks || 0,
    raw: p,
  }});
}
return out;

// Normaliza demografía de FB en formato long.
// Recibe MULTIPLES items concatenados (fans age/gender, fans country,
// fans city, reached age/gender). Distingue por metric name.
const PAGE_ID = '257587170945975';
const out = [];

const FAN_METRICS = {
  page_fans_gender_age: { audience_type: 'fan', dimension: 'age_gender' },
  page_fans_country: { audience_type: 'fan', dimension: 'country' },
  page_fans_city: { audience_type: 'fan', dimension: 'city' },
};
const REACHED_METRICS = {
  page_impressions_by_age_gender_unique: { audience_type: 'reached', dimension: 'age_gender' },
  page_impressions_by_country_unique: { audience_type: 'reached', dimension: 'country' },
  page_impressions_by_city_unique: { audience_type: 'reached', dimension: 'city' },
};
const ALL = { ...FAN_METRICS, ...REACHED_METRICS };

const todayIso = new Date().toISOString().slice(0, 10);

for (const item of items) {
  const data = item.json?.data || [];
  for (const m of data) {
    const meta = ALL[m.name];
    if (!meta) continue;
    // Lifetime metrics (fans_*): value es {key: number}, fecha = hoy (snapshot)
    // Day metrics (reached): values[] con end_time, value puede ser {key: number}
    if (meta.audience_type === 'fan') {
      // page_fans_*: una sola entrada en values con value como dict
      const v0 = (m.values || [])[0];
      const fecha = (v0?.end_time || todayIso + 'T00:00:00+0000').slice(0, 10);
      const dict = v0?.value;
      if (!dict || typeof dict !== 'object') continue;
      for (const [k, v] of Object.entries(dict)) {
        if (typeof v !== 'number') continue;
        out.push({ json: {
          fecha,
          page_id: PAGE_ID,
          audience_type: meta.audience_type,
          dimension: meta.dimension,
          category: String(k),
          value: v,
        }});
      }
    } else if (meta.audience_type === 'reached') {
      // page_impressions_by_*_unique: serie diaria, cada value es dict
      for (const vEntry of (m.values || [])) {
        const fecha = (vEntry.end_time || '').slice(0, 10);
        if (!fecha) continue;
        const dict = vEntry.value;
        if (!dict || typeof dict !== 'object') continue;
        for (const [k, v] of Object.entries(dict)) {
          if (typeof v !== 'number') continue;
          out.push({ json: {
            fecha,
            page_id: PAGE_ID,
            audience_type: meta.audience_type,
            dimension: meta.dimension,
            category: String(k),
            value: v,
          }});
        }
      }
    }
  }
}
return out;
